from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json
from leann import LeannBuilder

def export_index_metadata(
    index_path: str,
    output_file: str
) -> Dict[str, Any]:
    """Export index metadata and passage information to a JSON file.

Args:
    index_path: Path to the LEANN index file
    output_file: Path where the exported data will be saved

Returns:
    Dictionary containing:
    {
        "exported_passages": number of passages exported,
        "output_file": path to the output file,
        "status": "success" or "failed"
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Construct the metadata file path
        meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"

        # Check if metadata file exists
        if not meta_path.exists():
            raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

        # Load the metadata
        with open(meta_path, 'r', encoding='utf-8') as f:
            metadata = json.load(f)

        # Extract passage sources from metadata
        passage_sources = metadata.get('passage_sources', [])

        # Initialize passage collection
        passages = []

        # Process each passage source
        for source in passage_sources:
            source_type = source.get('type', 'jsonl')
            source_path = Path(source.get('path', ''))

            # Handle relative paths relative to metadata file directory
            if source_path.is_absolute():
                passage_file = source_path
            else:
                passage_file = Path(metadata.get('index_dir', '')) / source_path

            # Read passage file based on type
            if source_type == 'jsonl':
                try:
                    with open(passage_file, 'r', encoding='utf-8') as f:
                        for line_num, line in enumerate(f, 1):
                            if line.strip():
                                try:
                                    passage_data = json.loads(line.strip())
                                    passages.append({
                                        "id": passage_data.get("id", str(line_num)),
                                        "text": passage_data.get("text", "")
                                    })
                                except json.JSONDecodeError:
                                    continue
                except FileNotFoundError:
                    # Skip missing passage files
                    continue

        # Write passages to output file
        try:
            with open(output_file, 'w', encoding='utf-8') as f:
                for passage in passages:
                    json.dump({
                        "id": passage["id"],
                        "text": passage["text"]
                    }, f, ensure_ascii=False)
                    f.write('\n')

            return {
                "exported_passages": len(passages),
                "output_file": str(output_file),
                "status": "success"
            }

        except Exception as e:
            return {
                "exported_passages": 0,
                "output_file": str(output_file),
                "status": "failed",
                "error": str(e)
            }

    except FileNotFoundError as e:
        raise

def import_index_from_metadata(export_file: str, index_path: str, backend_name: str = 'hnsw') -> Dict[str, Any]:
    """Import and rebuild an index from exported metadata and passages.

Args:
    export_file: Path to the exported JSON file
    index_path: Path where the new index will be saved
    backend_name: Backend name for the new index (default: "hnsw")

Returns:
    Dictionary containing:
    {
        "index_path": path to the built index,
        "passages_imported": number of passages imported,
        "status": "success" or "failed"
    }

Raises:
    FileNotFoundError: If export file is not found
    ValueError: If export file format is invalid"""
    try:
        # Check if export file exists
        export_path = Path(export_file)
        if not export_path.exists():
            raise FileNotFoundError(f"Export file not found at {export_file}")

        # Validate export file format
        if export_path.suffix != '.jsonl':
            raise ValueError("Export file must be in JSONL format (.jsonl)")

        # Initialize passage counter
        passages_count = 0

        # Create LeannBuilder instance
        builder = LeannBuilder(
            backend_name=backend_name,
            embedding_model="facebook/contriever",  # Default model
            dimensions=None  # Will be auto-detected
        )

        # Read and process each passage
        with open(export_file, 'r', encoding='utf-8') as f:
            for line_num, line in enumerate(f, 1):
                if line.strip():
                    try:
                        passage_data = json.loads(line.strip())

                        # Validate required fields
                        if not isinstance(passage_data, dict):
                            raise ValueError(f"Invalid passage format at line {line_num}")

                        passage_id = passage_data.get("id")
                        text = passage_data.get("text", "")

                        if not passage_id or not text:
                            raise ValueError(f"Passage missing id or text at line {line_num}")

                        # Add passage to builder
                        builder.add_text(text, metadata={"id": passage_id})
                        passages_count += 1

                    except json.JSONDecodeError as e:
                        raise ValueError(f"JSON decode error at line {line_num}: {e}")
                    except Exception as e:
                        raise ValueError(f"Invalid passage data at line {line_num}: {e}")

        # Build the index
        try:
            builder.build_index(index_path)
            return {
                "index_path": index_path,
                "passages_imported": passages_count,
                "status": "success"
            }

        except Exception as e:
            return {
                "index_path": index_path,
                "passages_imported": passages_count,
                "status": "failed",
                "error": str(e)
            }

    except FileNotFoundError as e:
        raise
    except ValueError as e:
        raise
